#include <stdio.h>

void doubleIt(int *p) {
    *p = *p * 2;
}

int main() {
    int x = 10;
    int *p = &x;
    printf("x lives at %p\n", (void*)&x);
    printf("p points to %p\n", (void*)p);
    printf("Value at p: %d\n", *p);
    doubleIt(&x);
    printf("After doubleIt: %d\n", x);
    return 0;
}
